mapper.sql:
WHERE u.deleted = 0
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.mobile LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%'))
AND u.id = #{ds.userId}
AND u.dept_id IN
#{did}
AND 1 = 0

mapper.select:
SELECT
FROM sys_user u LEFT JOIN sys_dept d ON d.id = u.dept_id AND d.deleted = 0
ORDER BY u.id LIMIT #{limit} OFFSET #{offset}
